// Home.jsx (FINAL BEAUTIFUL VERSION)
import React from "react";
import "./Home.css";

export default function Home() {
  return (
    <div className="home-wrapper">
      {/* LOGO */}
      <img
        src="/prasa-logo.png"
        alt="PRASA Logo"
        className="home-logo"
      />

      {/* COMPANY NAME */}
      <h1 className="home-title">
        PRASA Infocom & Power Solutions Pvt. Ltd.
      </h1>

      {/* SUBTEXT */}
      <p className="home-subtitle">Welcome to the Employee Portal</p>

      {/* BUTTONS */}
      <div className="home-buttons">
        <a href="/profile" className="home-btn">Profile</a>
        <a href="/settings" className="home-btn">Settings</a>
      </div>
    </div>
  );
}
